import React, { Component } from 'react';
import './SNSLink.css';

class SNSLink extends Component {
    render() {
        const {
            mail,
            phone
        } = this.props;

        return (
            <div>
                <div className="Btn-title">{mail}</div>
                <div className="Btn-title">{phone}</div>
            </div>
        );
    }
}

export default SNSLink;
